mapper.select:
SELECT k.id AS id, k.tenant_id AS tenantId, t.tenant_code AS tenantCode, t.name AS tenantName, k.user_id AS userId, u.username AS username, u.display_name AS userDisplayName, k.name AS name, k.key_prefix AS keyPrefix, k.enabled AS enabled, k.expire_at AS expireAt, k.last_used_at AS lastUsedAt, k.created_at AS createdAt, k.updated_at AS updatedAt FROM api_key k INNER JOIN user_account u ON u.id = k.user_id INNER JOIN tenant t ON t.id = k.tenant_id WHERE k.deleted_at IS NULL AND k.tenant_id = #{tenantId} AND k.user_id = #{userId}
AND (k.name ILIKE CONCAT('%', #{keyword}, '%') OR k.key_prefix ILIKE CONCAT('%', #{keyword}, '%') OR u.username ILIKE CONCAT('%', #{keyword}, '%') OR u.display_name ILIKE CONCAT('%', #{keyword}, '%'))
AND k.enabled = TRUE AND (k.expire_at IS NULL OR k.expire_at > NOW())
AND k.enabled = FALSE AND (k.expire_at IS NULL OR k.expire_at > NOW())
AND k.expire_at IS NOT NULL AND k.expire_at <= NOW()
ORDER BY k.created_at DESC, k.id DESC LIMIT #{limit} OFFSET #{offset}
